import { type PropsWithChildren, type ReactElement } from 'react';
/**
 * Template for series actions in tooltips.
 * @public
 */
export type SeriesActionsTemplate = ReactElement<PropsWithChildren> | Promise<ReactElement<PropsWithChildren>>;
/**
 * Function type for generating series actions based on the data.
 * @public
 */
export type SeriesActions<T> = (item?: T) => SeriesActionsTemplate | undefined;
